const { exec } = require('child_process');
const fs = require('fs');

module.exports = async function (context, req) {
    context.log('JavaScript HTTP trigger function processed a request.');

    const inputFilename = req.body.inputFilename;
    const outputFormat = req.body.outputFormat;

    if (!inputFilename || !outputFormat) {
        return {
            status: 400,
            body: 'Both inputFilename and outputFormat are required.'
        };
    }

    const outputPath = `./${inputFilename}.${outputFormat}`;
    const command = `soffice --headless --convert-to ${outputFormat} --outdir ./ ${inputFilename}`;

    return new Promise((resolve, reject) => {
        exec(command, (error, stdout, stderr) => {
            if (error) {
                context.log.error(`Error executing LibreOffice: ${stderr}`);
                reject({
                    status: 500,
                    body: 'Failed to convert document.'
                });
            } else {
                fs.readFile(outputPath, (err, data) => {
                    if (err) {
                        context.log.error(`Error reading output file: ${err}`);
                        reject({
                            status: 500,
                            body: 'Failed to read converted document.'
                        });
                    } else {
                        context.res = {
                            status: 200,
                            headers: {
                                'Content-Type': `application/${outputFormat}`
                            },
                            body: data
                        };
                        resolve();
                    }
                });
            }
        });
    }).catch(error => {
        context.res = error;
    });
};